private maxHp = 100;
private currentHp = 100;
private hpBar!: Phaser.GameObjects.Graphics;

create() {
  this.hpBar = this.add.graphics().setScrollFactor(0).setDepth(100);
  this.drawHpBar();
}

drawHpBar() {
  this.hpBar.clear();
  this.hpBar.fillStyle(0x333333, 1);
  this.hpBar.fillRect(16, 50, 200, 16);
  const ratio = Math.max(0, this.currentHp / this.maxHp);
  this.hpBar.fillStyle(ratio > 0.3 ? 0x4ade80 : 0xef4444, 1);
  this.hpBar.fillRect(16, 50, 200 * ratio, 16);
}

takeDamage(amount: number) {
  this.currentHp = Math.max(0, this.currentHp - amount);
  this.drawHpBar();
  this.cameras.main.shake(100, 0.01);
  if (this.currentHp <= 0) this.gameOver();
}

