// Fire a projectile in an arc toward target
function fireProjectile(scene: Phaser.Scene, fromX: number, fromY: number, toX: number, toY: number) {
  const proj = scene.physics.add.sprite(fromX, fromY, "projectile");
  proj.body!.setAllowGravity(true);
  proj.body!.setGravityY(400);

  // Calculate velocity for parabolic arc
  const dx = toX - fromX;
  const dy = toY - fromY;
  const time = 1.0; // flight time in seconds
  const vx = dx / time;
  const vy = (dy - 0.5 * 400 * time * time) / time;

  proj.body!.setVelocity(vx, vy);
  proj.setRotation(Math.atan2(vy, vx));

  // Update rotation to follow arc in update()
  scene.events.on("update", () => {
    if (proj.active) {
      proj.setRotation(Math.atan2(proj.body!.velocity.y, proj.body!.velocity.x));
    }
  });

  // Destroy on ground hit
  scene.time.delayedCall(time * 1000 + 500, () => {
    if (proj.active) {
      scene.add.particles(proj.x, proj.y, "particle", { speed: 100, lifespan: 300, quantity: 10, emitting: false }).explode();
      proj.destroy();
    }
  });
  return proj;
}

// Wall jump mechanic
private isWallSliding = false;
private wallJumpTime = 0;

// In update():
const cursors = this.input.keyboard!.createCursorKeys();
const body = this.player.body!;
const onGround = body.touching.down;
const onWallLeft = body.touching.left;
const onWallRight = body.touching.right;
const onWall = (onWallLeft || onWallRight) && !onGround;

// Wall slide: slow fall when pressing against wall
if (onWall && body.velocity.y > 0) {
  this.isWallSliding = true;
  body.setVelocityY(50); // Slow slide speed
  this.player.setTint(0xaaaaff); // Visual feedback
} else {
  this.isWallSliding = false;
  this.player.clearTint();
}

// Wall jump
if (this.isWallSliding && Phaser.Input.Keyboard.JustDown(cursors.up)) {
  const jumpDir = onWallLeft ? 1 : -1;
  body.setVelocityY(-350);
  body.setVelocityX(250 * jumpDir);
  this.wallJumpTime = this.time.now;
}

// Normal movement (disable briefly after wall jump)
if (this.time.now - this.wallJumpTime > 200) {
  if (cursors.left.isDown) body.setVelocityX(-200);
  else if (cursors.right.isDown) body.setVelocityX(200);
  else body.setVelocityX(0);
}

// Normal jump
if (cursors.up.isDown && onGround) body.setVelocityY(-350);

// Apply knockback when player takes damage
function applyKnockback(target: Phaser.Physics.Arcade.Sprite, source: Phaser.Physics.Arcade.Sprite, force: number) {
  const angle = Phaser.Math.Angle.Between(source.x, source.y, target.x, target.y);
  const vx = Math.cos(angle) * force;
  const vy = Math.sin(angle) * force;
  target.body!.setVelocity(vx, vy);
}

// Usage in collision callback:
this.physics.add.overlap(this.player, this.enemies, (player, enemy) => {
  const p = player as Phaser.Physics.Arcade.Sprite;
  const e = enemy as Phaser.Physics.Arcade.Sprite;
  if (this.invulnerable) return;

  this.takeDamage(10);
  applyKnockback(p, e, 300);

  // Invulnerability frames
  this.invulnerable = true;
  this.tweens.add({
    targets: p, alpha: 0.5, duration: 100, yoyo: true, repeat: 5,
    onComplete: () => { this.invulnerable = false; p.setAlpha(1); }
  });
}, null, this);

// Slope handling using tilemap collision with slope tiles
// Method 1: Use tilemap with collision shapes
