// Method 2: Manual slope with polygon body (simulated with ramp sprites)
function createSlope(scene: Phaser.Scene, x: number, y: number, width: number, height: number) {
  // Use multiple thin static platforms to approximate a slope
  const steps = 8;
  const stepW = width / steps;
  const stepH = height / steps;
  const group = scene.physics.add.staticGroup();
  for (let i = 0; i < steps; i++) {
    const sx = x + i * stepW + stepW / 2;
    const sy = y - i * stepH;
    const step = group.create(sx, sy, "step");
    step.setDisplaySize(stepW + 2, 6).refreshBody();
  }
  return group;
}

// Player sticks to slope (prevent bouncing)
// In update(): if on slope and grounded, apply small downward force
if (this.player.body!.touching.down && Math.abs(this.player.body!.velocity.x) > 0) {
  this.player.body!.setGravityY(600); // Extra gravity on slopes
} else {
  this.player.body!.setGravityY(300);
}

// Simulated chain/rope using connected sprites and tweens
function createRope(scene: Phaser.Scene, startX: number, startY: number, segments: number, segLen: number) {
  const links: Phaser.GameObjects.Sprite[] = [];
  for (let i = 0; i < segments; i++) {
    const link = scene.add.sprite(startX, startY + i * segLen, "chain-link");
    links.push(link);
  }

  // Swing animation using chained tweens
  const swingDuration = 1500;
  links.forEach((link, i) => {
    const delay = i * 50; // cascade effect
    const amplitude = 20 + i * 5; // more swing at bottom
    scene.tweens.add({
      targets: link,
      x: startX + amplitude,
      duration: swingDuration,
      yoyo: true,
      repeat: -1,
      ease: "Sine.InOut",
      delay: delay
    });
  });

  return links;
}

// Grab rope: attach player to last link
function grabRope(player: Phaser.Physics.Arcade.Sprite, ropeEnd: Phaser.GameObjects.Sprite) {
  player.body!.setAllowGravity(false);
  player.body!.setVelocity(0, 0);
  // Follow rope end in update
  player.x = ropeEnd.x;
  player.y = ropeEnd.y + 20;
}

// Create bounce pads that launch player upward
const bouncePads = this.physics.add.staticGroup();
const pad = bouncePads.create(400, 550, "bounce-pad");

this.physics.add.collider(this.player, bouncePads, (player, pad) => {
  const p = player as Phaser.Physics.Arcade.Sprite;
  const b = pad as Phaser.Physics.Arcade.Sprite;
  // Only bounce if landing on top
  if (p.body!.touching.down) {
    p.body!.setVelocityY(-600); // Strong upward launch
    // Squash & stretch animation on pad
    this.tweens.add({
      targets: b, scaleY: 0.5, duration: 100, yoyo: true, ease: "Bounce.Out"
    });
    // Player stretch
    this.tweens.add({
      targets: p, scaleY: 1.3, scaleX: 0.8, duration: 150, yoyo: true
    });
  }
}, null, this);

// Directional bounce (angled launch)
