// Game state management with enum
enum GameState {
  PLAYING = "PLAYING",
  PAUSED = "PAUSED",
  GAMEOVER = "GAMEOVER",
  VICTORY = "VICTORY"
}

private gameState = GameState.PLAYING;
private pauseOverlay!: Phaser.GameObjects.Rectangle;
private pauseText!: Phaser.GameObjects.Text;

create() {
  const { width, height } = this.scale;
  this.pauseOverlay = this.add.rectangle(width / 2, height / 2, width, height, 0x000000, 0.6)
    .setScrollFactor(0).setDepth(500).setVisible(false);
  this.pauseText = this.add.text(width / 2, height / 2, "PAUSED", { fontSize: "48px", color: "#fff" })
    .setOrigin(0.5).setScrollFactor(0).setDepth(501).setVisible(false);

  // ESC to toggle pause
  this.input.keyboard!.on("keydown-ESC", () => {
    if (this.gameState === GameState.PLAYING) this.setState(GameState.PAUSED);
    else if (this.gameState === GameState.PAUSED) this.setState(GameState.PLAYING);
  });
}

setState(newState: GameState) {
  this.gameState = newState;
  switch (newState) {
    case GameState.PAUSED:
      this.physics.pause();
      this.pauseOverlay.setVisible(true);
      this.pauseText.setVisible(true);
      break;
    case GameState.PLAYING:
      this.physics.resume();
      this.pauseOverlay.setVisible(false);
      this.pauseText.setVisible(false);
      break;
    case GameState.GAMEOVER:
      this.physics.pause();
      this.time.delayedCall(1500, () => this.scene.start("GameOverScene"));
      break;
  }
}

update() {
  if (this.gameState !== GameState.PLAYING) return;
  // Normal game logic here...
}

// Inventory with add/remove/count/has
interface InventoryItem {
  id: string;
  name: string;
  icon: string;
  quantity: number;
  maxStack: number;
}

class Inventory {
  private items: Map<string, InventoryItem> = new Map();
  private maxSlots: number;

  constructor(maxSlots = 20) { this.maxSlots = maxSlots; }

  add(id: string, name: string, icon: string, quantity = 1, maxStack = 99): boolean {
    if (this.items.has(id)) {
      const item = this.items.get(id)!;
      item.quantity = Math.min(item.quantity + quantity, item.maxStack);
      return true;
    }
    if (this.items.size >= this.maxSlots) return false;
    this.items.set(id, { id, name, icon, quantity, maxStack });
    return true;
  }

  remove(id: string, quantity = 1): boolean {
    const item = this.items.get(id);
    if (!item || item.quantity < quantity) return false;
    item.quantity -= quantity;
    if (item.quantity <= 0) this.items.delete(id);
    return true;
  }

  has(id: string, quantity = 1): boolean {
    const item = this.items.get(id);
    return item !== undefined && item.quantity >= quantity;
  }

  count(id: string): number {
    return this.items.get(id)?.quantity ?? 0;
  }

  getAll(): InventoryItem[] { return Array.from(this.items.values()); }
}

