// Dialog with branching choices
interface DialogNode {
  text: string;
  choices?: { label: string; next: string; effect?: () => void }[];
  next?: string; // auto-advance if no choices
}

const dialogTree: Record<string, DialogNode> = {
  "start": { text: "Hello traveler! What brings you here?", choices: [
    { label: "I need supplies", next: "shop" },
    { label: "Any quests?", next: "quest" },
    { label: "Goodbye", next: "end" }
  ]},
  "shop": { text: "Take a look at my wares!", next: "end" },
  "quest": { text: "Defeat 5 slimes in the forest.", choices: [
    { label: "I accept!", next: "quest-accept", effect: () => { /* start quest */ } },
    { label: "Not now", next: "end" }
  ]},
  "quest-accept": { text: "Good luck, adventurer!", next: "end" },
  "end": { text: "" }
};

function showDialog(scene: Phaser.Scene, nodeId: string) {
  const node = dialogTree[nodeId];
  if (!node || nodeId === "end") { hideDialog(); return; }
  dialogText.setText(node.text);
  // Clear old choice buttons
  choiceButtons.forEach(b => b.destroy());
  choiceButtons = [];
  if (node.choices) {
    node.choices.forEach((choice, i) => {
      const btn = scene.add.text(50, 420 + i * 30, `> ${choice.label}`, { fontSize: "16px", color: "#4ade80" })
        .setInteractive({ useHandCursor: true }).setScrollFactor(0).setDepth(210);
      btn.on("pointerdown", () => { choice.effect?.(); showDialog(scene, choice.next); });
      choiceButtons.push(btn);
    });
  } else if (node.next) {
    scene.input.once("pointerdown", () => showDialog(scene, node.next!));
  }
}

// Quest system with objectives
interface QuestObjective {
  description: string;
  current: number;
  target: number;
  completed: boolean;
}

interface Quest {
  id: string;
  title: string;
  description: string;
  objectives: QuestObjective[];
  reward: { gold?: number; xp?: number; item?: string };
  completed: boolean;
}

class QuestManager {
  private quests: Map<string, Quest> = new Map();

  addQuest(quest: Quest) { this.quests.set(quest.id, quest); }

  updateObjective(questId: string, objIndex: number, amount = 1) {
    const quest = this.quests.get(questId);
    if (!quest || quest.completed) return;
    const obj = quest.objectives[objIndex];
    obj.current = Math.min(obj.current + amount, obj.target);
    if (obj.current >= obj.target) obj.completed = true;
    // Check if all objectives complete
    if (quest.objectives.every(o => o.completed)) {
      quest.completed = true;
      this.onQuestComplete(quest);
    }
  }

  private onQuestComplete(quest: Quest) {
    console.log(`Quest complete: ${quest.title}`);
    // Grant rewards
  }

  getActive(): Quest[] {
    return Array.from(this.quests.values()).filter(q => !q.completed);
  }
}

