// Save/load game state
interface SaveData {
  level: number;
  score: number;
  playerX: number;
  playerY: number;
  health: number;
  inventory: { id: string; qty: number }[];
  completedQuests: string[];
  timestamp: number;
}

function saveGame(scene: Phaser.Scene, slot = "save1"): void {
  const data: SaveData = {
    level: scene.currentLevel,
    score: scene.score,
    playerX: scene.player.x,
    playerY: scene.player.y,
    health: scene.currentHp,
    inventory: scene.inventory.getAll().map(i => ({ id: i.id, qty: i.quantity })),
    completedQuests: scene.questManager.getCompleted().map(q => q.id),
    timestamp: Date.now()
  };
  localStorage.setItem(slot, JSON.stringify(data));
}

function loadGame(slot = "save1"): SaveData | null {
  const raw = localStorage.getItem(slot);
  if (!raw) return null;
  try { return JSON.parse(raw) as SaveData; }
  catch { return null; }
}

function hasSaveData(slot = "save1"): boolean {
  return localStorage.getItem(slot) !== null;
}

function deleteSave(slot = "save1"): void {
  localStorage.removeItem(slot);
}

