// Achievement system with unlock conditions
interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  unlocked: boolean;
  condition: () => boolean;
}

class AchievementManager {
  private achievements: Achievement[] = [];
  private scene: Phaser.Scene;

  constructor(scene: Phaser.Scene) { this.scene = scene; }

  register(ach: Omit<Achievement, "unlocked">) {
    this.achievements.push({ ...ach, unlocked: false });
  }

  check() {
    this.achievements.forEach(ach => {
      if (!ach.unlocked && ach.condition()) {
        ach.unlocked = true;
        this.showNotification(ach);
      }
    });
  }

  private showNotification(ach: Achievement) {
    const { width } = this.scene.scale;
    const bg = this.scene.add.rectangle(width / 2, -50, 300, 60, 0x1e293b, 0.95)
      .setScrollFactor(0).setDepth(1000).setStrokeStyle(2, 0xfbbf24);
    const text = this.scene.add.text(width / 2, -50, `Achievement: ${ach.title}`, {
      fontSize: "16px", color: "#fbbf24"
    }).setOrigin(0.5).setScrollFactor(0).setDepth(1001);

    // Slide in and out
    this.scene.tweens.add({
      targets: [bg, text], y: 40, duration: 500, ease: "Back.Out",
      hold: 2000, yoyo: true,
      onComplete: () => { bg.destroy(); text.destroy(); }
    });
  }
}

