// Power-up with timed effect
enum PowerUpType { SPEED, INVINCIBLE, DOUBLE_POINTS, MAGNET }

interface ActivePowerUp {
  type: PowerUpType;
  remaining: number;
  timer: Phaser.Time.TimerEvent;
}

private activePowerUps: Map<PowerUpType, ActivePowerUp> = new Map();

function collectPowerUp(scene: Phaser.Scene, type: PowerUpType, duration: number) {
  // Remove existing if same type (refresh)
  if (scene.activePowerUps.has(type)) {
    scene.activePowerUps.get(type)!.timer.destroy();
  }

  const timer = scene.time.delayedCall(duration, () => {
    scene.activePowerUps.delete(type);
    onPowerUpEnd(scene, type);
  });

  scene.activePowerUps.set(type, { type, remaining: duration, timer });
  onPowerUpStart(scene, type);
}

function onPowerUpStart(scene: Phaser.Scene, type: PowerUpType) {
  switch (type) {
    case PowerUpType.SPEED:
      scene.playerSpeed = 400; // doubled
      break;
    case PowerUpType.INVINCIBLE:
      scene.invulnerable = true;
      scene.player.setTint(0xffd700);
      break;
    case PowerUpType.DOUBLE_POINTS:
      scene.scoreMultiplier = 2;
      break;
  }
}

function onPowerUpEnd(scene: Phaser.Scene, type: PowerUpType) {
  switch (type) {
    case PowerUpType.SPEED: scene.playerSpeed = 200; break;
    case PowerUpType.INVINCIBLE: scene.invulnerable = false; scene.player.clearTint(); break;
    case PowerUpType.DOUBLE_POINTS: scene.scoreMultiplier = 1; break;
  }
}

function hasPowerUp(scene: Phaser.Scene, type: PowerUpType): boolean {
  return scene.activePowerUps.has(type);
}

// Combo system with timeout reset
private comboCount = 0;
private comboMultiplier = 1;
private comboTimer: Phaser.Time.TimerEvent | null = null;
private comboText!: Phaser.GameObjects.Text;

create() {
  this.comboText = this.add.text(this.scale.width - 16, 16, "", {
    fontSize: "24px", color: "#fbbf24", fontStyle: "bold"
  }).setOrigin(1, 0).setScrollFactor(0).setDepth(100);
}

addCombo() {
  this.comboCount++;
  // Multiplier tiers
  if (this.comboCount >= 20) this.comboMultiplier = 4;
  else if (this.comboCount >= 10) this.comboMultiplier = 3;
  else if (this.comboCount >= 5) this.comboMultiplier = 2;
  else this.comboMultiplier = 1;

  this.comboText.setText(`${this.comboCount}x COMBO (x${this.comboMultiplier})`);
  this.tweens.add({ targets: this.comboText, scale: 1.3, duration: 80, yoyo: true });

  // Reset timer on each hit
  if (this.comboTimer) this.comboTimer.destroy();
  this.comboTimer = this.time.delayedCall(2000, () => this.resetCombo());
}

resetCombo() {
  this.comboCount = 0;
  this.comboMultiplier = 1;
  this.comboText.setText("");
}

// Get effective score with combo
getScore(basePoints: number): number {
  return basePoints * this.comboMultiplier;
}

// Wave spawner with increasing difficulty
private currentWave = 0;
private enemiesRemaining = 0;
private waveActive = false;
private waveText!: Phaser.GameObjects.Text;

startWave() {
  this.currentWave++;
  const enemyCount = 3 + this.currentWave * 2; // More enemies each wave
  const spawnDelay = Math.max(300, 1000 - this.currentWave * 100); // Faster spawns
  this.enemiesRemaining = enemyCount;
  this.waveActive = true;

  // Show wave announcement
  this.waveText = this.add.text(this.scale.width / 2, this.scale.height / 2, `Wave ${this.currentWave}`, {
    fontSize: "48px", color: "#ef4444", fontStyle: "bold"
  }).setOrigin(0.5).setDepth(200);
  this.tweens.add({ targets: this.waveText, alpha: 0, scale: 2, duration: 1500, onComplete: () => this.waveText.destroy() });

  // Spawn enemies over time
  let spawned = 0;
  this.time.addEvent({
    delay: spawnDelay,
    repeat: enemyCount - 1,
    callback: () => {
      spawned++;
      this.spawnEnemy(this.currentWave);
    }
  });
}

spawnEnemy(wave: number) {
  const x = Phaser.Math.Between(50, this.scale.width - 50);
  const enemy = this.enemies.getFirst(false, true, x, 0, "enemy");
  if (enemy) {
    enemy.setActive(true).setVisible(true);
    enemy.body!.setVelocityY(50 + wave * 10); // Faster with waves
    (enemy as any).hp = 1 + Math.floor(wave / 3); // More HP over time
  }
}

onEnemyKilled() {
  this.enemiesRemaining--;
  if (this.enemiesRemaining <= 0 && this.waveActive) {
    this.waveActive = false;
    this.time.delayedCall(2000, () => this.startWave()); // Next wave after delay
  }
}

// Minimap using a second camera
create() {
  const mapWidth = 2000;
