  // Minimap camera
  const minimap = this.cameras.add(
    this.scale.width - minimapSize - padding,
    padding,
    minimapSize,
    minimapSize
  );
  minimap.setZoom(minimapSize / mapWidth); // Fit entire world
  minimap.setBackgroundColor(0x1e293b);
  minimap.startFollow(this.player);
  minimap.setAlpha(0.8);

  // Optional: border around minimap
  const border = this.add.rectangle(
    this.scale.width - minimapSize / 2 - padding,
    minimapSize / 2 + padding,
    minimapSize + 4, minimapSize + 4
  ).setStrokeStyle(2, 0xffffff).setFillStyle(0x000000, 0).setScrollFactor(0).setDepth(999);

  // Make border only visible to main camera
  minimap.ignore(border);
}

