// Local leaderboard with sorted entries
interface LeaderboardEntry {
  name: string;
  score: number;
  date: string;
}

const LEADERBOARD_KEY = "game-leaderboard";
const MAX_ENTRIES = 10;

function getLeaderboard(): LeaderboardEntry[] {
  const raw = localStorage.getItem(LEADERBOARD_KEY);
  if (!raw) return [];
  try { return JSON.parse(raw); }
  catch { return []; }
}

function addScore(name: string, score: number): number {
  const entries = getLeaderboard();
  entries.push({ name, score, date: new Date().toLocaleDateString() });
  entries.sort((a, b) => b.score - a.score);
  const trimmed = entries.slice(0, MAX_ENTRIES);
  localStorage.setItem(LEADERBOARD_KEY, JSON.stringify(trimmed));
  return trimmed.findIndex(e => e.name === name && e.score === score) + 1; // rank
}

function isHighScore(score: number): boolean {
  const entries = getLeaderboard();
  return entries.length < MAX_ENTRIES || score > (entries[entries.length - 1]?.score ?? 0);
}

// Display leaderboard
function showLeaderboard(scene: Phaser.Scene) {
  const { width, height } = scene.scale;
  const entries = getLeaderboard();
  scene.add.text(width / 2, 60, "HIGH SCORES", { fontSize: "32px", color: "#fbbf24" }).setOrigin(0.5);
  entries.forEach((entry, i) => {
    const y = 120 + i * 35;
    const color = i === 0 ? "#fbbf24" : i < 3 ? "#94a3b8" : "#64748b";
    scene.add.text(width / 2 - 120, y, `${i + 1}. ${entry.name}`, { fontSize: "18px", color }).setOrigin(0, 0.5);
    scene.add.text(width / 2 + 120, y, String(entry.score), { fontSize: "18px", color }).setOrigin(1, 0.5);
  });
}

// Adaptive difficulty based on player performance
class DifficultyManager {
  private level = 1; // 1-5 scale
  private recentDeaths = 0;
  private recentKills = 0;
  private checkInterval: Phaser.Time.TimerEvent;

  constructor(private scene: Phaser.Scene) {
    // Check every 30 seconds
    this.checkInterval = scene.time.addEvent({
      delay: 30000, loop: true, callback: () => this.adjust()
    });
  }

  private adjust() {
    const killRatio = this.recentKills / Math.max(1, this.recentDeaths);
    if (killRatio > 5 && this.level < 5) this.level++; // Too easy
    else if (killRatio < 1 && this.level > 1) this.level--; // Too hard
    this.recentDeaths = 0;
    this.recentKills = 0;
  }

  onPlayerDeath() { this.recentDeaths++; }
  onEnemyKilled() { this.recentKills++; }

  getEnemySpeed(): number { return 80 + this.level * 30; }
  getSpawnRate(): number { return Math.max(500, 2000 - this.level * 300); }
  getEnemyHP(): number { return this.level; }
  getLevel(): number { return this.level; }
}

