// Lives system with respawn
private lives = 3;
private livesText!: Phaser.GameObjects.Text;
private spawnPoint = { x: 100, y: 400 };
private isDead = false;

create() {
  this.livesText = this.add.text(16, 80, "Lives: 3", { fontSize: "20px", color: "#fff" })
    .setScrollFactor(0).setDepth(100);
}

die() {
  if (this.isDead) return;
  this.isDead = true;
  this.lives--;
  this.livesText.setText(`Lives: ${this.lives}`);

  // Death animation
  this.player.body!.setVelocity(0, -200);
  this.player.setTint(0xff0000);
  this.physics.pause();

  if (this.lives <= 0) {
    this.time.delayedCall(1500, () => {
      this.scene.start("GameOverScene", { score: this.score });
    });
  } else {
    this.time.delayedCall(1500, () => this.respawn());
  }
}

respawn() {
  this.isDead = false;
  this.physics.resume();
  this.player.setPosition(this.spawnPoint.x, this.spawnPoint.y);
  this.player.clearTint();
  this.player.body!.setVelocity(0, 0);
  this.currentHp = this.maxHp;
  this.drawHpBar();

  // Brief invulnerability
  this.invulnerable = true;
  this.tweens.add({
    targets: this.player, alpha: 0.3, duration: 150, yoyo: true, repeat: 6,
    onComplete: () => { this.invulnerable = false; this.player.setAlpha(1); }
  });
}

addLife() {
  this.lives++;
  this.livesText.setText(`Lives: ${this.lives}`);
  this.cameras.main.flash(300, 100, 255, 100);
}

// Reusable button with hover/press states
function createButton(
  scene: Phaser.Scene, x: number, y: number, text: string,
  onClick: () => void, style?: { width?: number; height?: number; color?: number }
) {
  const w = style?.width ?? 180;
  const h = style?.height ?? 50;
  const color = style?.color ?? 0x4ade80;

  const bg = scene.add.rectangle(x, y, w, h, color, 1)
    .setStrokeStyle(2, 0xffffff)
    .setInteractive({ useHandCursor: true });
  const label = scene.add.text(x, y, text, {
    fontSize: "20px", color: "#fff", fontStyle: "bold"
  }).setOrigin(0.5);

  bg.on("pointerover", () => {
    bg.setFillStyle(Phaser.Display.Color.ValueToColor(color).lighten(30).color);
    scene.tweens.add({ targets: [bg, label], scale: 1.05, duration: 100 });
  });
  bg.on("pointerout", () => {
    bg.setFillStyle(color);
    scene.tweens.add({ targets: [bg, label], scale: 1, duration: 100 });
  });
  bg.on("pointerdown", () => {
    scene.tweens.add({ targets: [bg, label], scale: 0.95, duration: 50, yoyo: true });
    onClick();
  });

  return { bg, label };
}

