// Reusable progress bar
class ProgressBar {
  private bg: Phaser.GameObjects.Rectangle;
  private fill: Phaser.GameObjects.Rectangle;
  private label?: Phaser.GameObjects.Text;
  private maxWidth: number;

  constructor(
    scene: Phaser.Scene, x: number, y: number,
    width: number, height: number,
    options?: { bgColor?: number; fillColor?: number; showLabel?: boolean }
  ) {
    const bgColor = options?.bgColor ?? 0x333333;
    const fillColor = options?.fillColor ?? 0x4ade80;

    this.maxWidth = width;
    this.bg = scene.add.rectangle(x, y, width, height, bgColor).setOrigin(0, 0.5);
    this.fill = scene.add.rectangle(x, y, 0, height - 4, fillColor).setOrigin(0, 0.5);

    if (options?.showLabel) {
      this.label = scene.add.text(x + width / 2, y, "0%", {
        fontSize: "12px", color: "#fff"
      }).setOrigin(0.5);
    }
  }

  setValue(ratio: number) {
    const clamped = Phaser.Math.Clamp(ratio, 0, 1);
    this.fill.width = this.maxWidth * clamped;
    if (this.label) this.label.setText(`${Math.floor(clamped * 100)}%`);
    // Color shift: green -> yellow -> red
    if (clamped < 0.3) this.fill.setFillStyle(0xef4444);
    else if (clamped < 0.6) this.fill.setFillStyle(0xfbbf24);
    else this.fill.setFillStyle(0x4ade80);
  }

  setScrollFactor(n: number) {
    this.bg.setScrollFactor(n);
    this.fill.setScrollFactor(n);
    this.label?.setScrollFactor(n);
    return this;
  }

  setDepth(n: number) {
    this.bg.setDepth(n);
    this.fill.setDepth(n + 1);
    this.label?.setDepth(n + 2);
    return this;
  }
}

