// Typewriter effect dialog box
class TypewriterDialog {
  private bg: Phaser.GameObjects.Graphics;
  private text: Phaser.GameObjects.Text;
  private continueIcon: Phaser.GameObjects.Text;
  private fullText = "";
  private currentChar = 0;
  private timer: Phaser.Time.TimerEvent | null = null;
  private isTyping = false;
  private scene: Phaser.Scene;

  constructor(scene: Phaser.Scene) {
    this.scene = scene;
    const { width, height } = scene.scale;
    this.bg = scene.add.graphics().setScrollFactor(0).setDepth(200);
    this.bg.fillStyle(0x000000, 0.85);
    this.bg.fillRoundedRect(30, height - 130, width - 60, 110, 10);
    this.bg.lineStyle(2, 0x4ade80);
    this.bg.strokeRoundedRect(30, height - 130, width - 60, 110, 10);

    this.text = scene.add.text(50, height - 120, "", {
      fontSize: "16px", color: "#fff", wordWrap: { width: width - 100 }, lineSpacing: 4
    }).setScrollFactor(0).setDepth(201);

    this.continueIcon = scene.add.text(width - 60, height - 40, ">>>", {
      fontSize: "14px", color: "#4ade80"
    }).setScrollFactor(0).setDepth(201).setVisible(false);
    scene.tweens.add({ targets: this.continueIcon, alpha: 0.3, duration: 500, yoyo: true, repeat: -1 });

    this.hide();
  }

  show(message: string, speed = 30) {
    this.bg.setVisible(true); this.text.setVisible(true);
    this.fullText = message;
    this.currentChar = 0;
    this.text.setText("");
    this.isTyping = true;
    this.continueIcon.setVisible(false);
    this.timer = this.scene.time.addEvent({
      delay: speed, loop: true,
      callback: () => {
        this.currentChar++;
        this.text.setText(this.fullText.slice(0, this.currentChar));
        if (this.currentChar >= this.fullText.length) {
          this.timer?.destroy(); this.isTyping = false;
          this.continueIcon.setVisible(true);
        }
      }
    });
  }

  skip() {
    if (this.isTyping) {
      this.timer?.destroy(); this.isTyping = false;
      this.text.setText(this.fullText);
      this.continueIcon.setVisible(true);
    }
  }

  hide() { this.bg.setVisible(false); this.text.setVisible(false); this.continueIcon.setVisible(false); }
}

// Settings scene with volume slider and toggles
class SettingsScene extends Phaser.Scene {
  constructor() { super("SettingsScene"); }

  create() {
    const { width, height } = this.scale;
    this.add.rectangle(0, 0, width, height, 0x0f172a, 0.95).setOrigin(0);
    this.add.text(width / 2, 50, "Settings", { fontSize: "36px", color: "#fff" }).setOrigin(0.5);

    // Volume slider
    let volume = Number(localStorage.getItem("volume") ?? "0.7");
    this.add.text(width / 2 - 150, 140, "Volume", { fontSize: "20px", color: "#fff" });
    const sliderBg = this.add.rectangle(width / 2 + 50, 150, 200, 8, 0x334155).setOrigin(0, 0.5);
    const sliderKnob = this.add.circle(width / 2 + 50 + volume * 200, 150, 12, 0x4ade80)
      .setInteractive({ draggable: true, useHandCursor: true });
    const volText = this.add.text(width / 2 + 270, 150, `${Math.round(volume * 100)}%`, {
      fontSize: "16px", color: "#94a3b8"
    }).setOrigin(0, 0.5);

    this.input.setDraggable(sliderKnob);
    this.input.on("drag", (p: any, obj: any, dx: number) => {
      if (obj !== sliderKnob) return;
      const minX = sliderBg.x;
      const maxX = sliderBg.x + 200;
      sliderKnob.x = Phaser.Math.Clamp(dx, minX, maxX);
      volume = (sliderKnob.x - minX) / 200;
      volText.setText(`${Math.round(volume * 100)}%`);
      localStorage.setItem("volume", String(volume));
    });

    // Toggle: SFX on/off
    let sfxOn = localStorage.getItem("sfx") !== "false";
    const sfxBtn = this.add.text(width / 2, 220, `SFX: ${sfxOn ? "ON" : "OFF"}`, {
      fontSize: "20px", color: sfxOn ? "#4ade80" : "#ef4444"
    }).setOrigin(0.5).setInteractive({ useHandCursor: true });
    sfxBtn.on("pointerdown", () => {
      sfxOn = !sfxOn;
      sfxBtn.setText(`SFX: ${sfxOn ? "ON" : "OFF"}`).setColor(sfxOn ? "#4ade80" : "#ef4444");
      localStorage.setItem("sfx", String(sfxOn));
    });

    // Back button
    const back = this.add.text(width / 2, height - 60, "Back", { fontSize: "22px", color: "#06b6d4" })
      .setOrigin(0.5).setInteractive({ useHandCursor: true });
    back.on("pointerdown", () => this.scene.stop());
  }
}

