// Simple virtual joystick for mobile
class VirtualJoystick {
  private base: Phaser.GameObjects.Circle;
  private knob: Phaser.GameObjects.Circle;
  private pointer: Phaser.Input.Pointer | null = null;
  public forceX = 0;
  public forceY = 0;
  private radius: number;

  constructor(scene: Phaser.Scene, x: number, y: number, radius = 60) {
    this.radius = radius;
    this.base = scene.add.circle(x, y, radius, 0x333333, 0.5).setScrollFactor(0).setDepth(900);
    this.knob = scene.add.circle(x, y, radius * 0.4, 0x4ade80, 0.8).setScrollFactor(0).setDepth(901);

    scene.input.on("pointerdown", (p: Phaser.Input.Pointer) => {
      if (p.x < scene.scale.width / 2) { this.pointer = p; } // Left side only
    });
    scene.input.on("pointerup", (p: Phaser.Input.Pointer) => {
      if (p === this.pointer) { this.pointer = null; this.reset(); }
    });
  }

  update() {
    if (!this.pointer || !this.pointer.isDown) { this.reset(); return; }
    const dx = this.pointer.x - this.base.x;
    const dy = this.pointer.y - this.base.y;
    const dist = Math.min(Math.sqrt(dx * dx + dy * dy), this.radius);
    const angle = Math.atan2(dy, dx);
    this.knob.x = this.base.x + Math.cos(angle) * dist;
    this.knob.y = this.base.y + Math.sin(angle) * dist;
    this.forceX = Math.cos(angle) * (dist / this.radius);
    this.forceY = Math.sin(angle) * (dist / this.radius);
  }

  private reset() {
    this.knob.x = this.base.x; this.knob.y = this.base.y;
    this.forceX = 0; this.forceY = 0;
  }
}

