// Modal popup overlay
function showModal(
  scene: Phaser.Scene, title: string, message: string,
  onConfirm: () => void, onCancel?: () => void
) {
  const { width, height } = scene.scale;
  const elements: Phaser.GameObjects.GameObject[] = [];

  // Backdrop
  const backdrop = scene.add.rectangle(width / 2, height / 2, width, height, 0x000000, 0.6)
    .setScrollFactor(0).setDepth(800).setInteractive(); // Block clicks behind
  elements.push(backdrop);

  // Modal box
  const box = scene.add.rectangle(width / 2, height / 2, 320, 200, 0x1e293b)
    .setStrokeStyle(2, 0x4ade80).setScrollFactor(0).setDepth(801);
  elements.push(box);

  // Title
  const titleText = scene.add.text(width / 2, height / 2 - 60, title, {
    fontSize: "22px", color: "#fff", fontStyle: "bold"
  }).setOrigin(0.5).setScrollFactor(0).setDepth(802);
  elements.push(titleText);

  // Message
  const msgText = scene.add.text(width / 2, height / 2 - 10, message, {
    fontSize: "16px", color: "#94a3b8", wordWrap: { width: 280 }, align: "center"
  }).setOrigin(0.5).setScrollFactor(0).setDepth(802);
  elements.push(msgText);

  function closeModal() { elements.forEach(e => e.destroy()); }

  // Confirm button
  const confirmBtn = scene.add.text(width / 2 - 60, height / 2 + 60, "Confirm", {
    fontSize: "18px", color: "#4ade80"
  }).setOrigin(0.5).setScrollFactor(0).setDepth(802).setInteractive({ useHandCursor: true });
  confirmBtn.on("pointerdown", () => { closeModal(); onConfirm(); });
  elements.push(confirmBtn);

  // Cancel button
  if (onCancel) {
    const cancelBtn = scene.add.text(width / 2 + 60, height / 2 + 60, "Cancel", {
      fontSize: "18px", color: "#ef4444"
    }).setOrigin(0.5).setScrollFactor(0).setDepth(802).setInteractive({ useHandCursor: true });
    cancelBtn.on("pointerdown", () => { closeModal(); onCancel(); });
    elements.push(cancelBtn);
  }

  // Animate in
  box.setScale(0);
  scene.tweens.add({ targets: box, scale: 1, duration: 200, ease: "Back.Out" });
}

