// Custom shake using tween (more control)
function customShake(scene: Phaser.Scene, target: Phaser.GameObjects.GameObject, intensity: number, duration: number) {
  const originalX = (target as any).x;
  const originalY = (target as any).y;
  scene.tweens.add({
    targets: target,
    x: { from: originalX - intensity, to: originalX + intensity },
    y: { from: originalY - intensity / 2, to: originalY + intensity / 2 },
    duration: 50,
    yoyo: true,
    repeat: Math.floor(duration / 100),
    onComplete: () => { (target as any).x = originalX; (target as any).y = originalY; }
  });
}

// Multi-stage death animation
function playDeathAnimation(scene: Phaser.Scene, sprite: Phaser.Physics.Arcade.Sprite, onComplete?: () => void) {
  sprite.body!.setVelocity(0, 0);
  sprite.body!.setAllowGravity(false);

  // Flash red
  scene.tweens.add({
    targets: sprite,
    alpha: 0.2,
    duration: 60,
    yoyo: true,
    repeat: 3,
    onStart: () => sprite.setTint(0xff0000)
  });

  // Then shrink and fade
  scene.time.delayedCall(300, () => {
    scene.tweens.add({
      targets: sprite,
      scale: 0,
      alpha: 0,
      angle: 360,
      duration: 400,
      ease: "Power2",
      onComplete: () => {
        sprite.destroy();
        onComplete?.();
      }
    });
  });

  // Particles
  scene.add.particles(sprite.x, sprite.y, "particle", {
