// Afterimage trail (sprite copies)
function createAfterimageTrail(scene: Phaser.Scene, target: Phaser.Physics.Arcade.Sprite) {
  const trail: Phaser.GameObjects.Sprite[] = [];
  scene.time.addEvent({
    delay: 50, loop: true,
    callback: () => {
      if (Math.abs(target.body!.velocity.x) < 50 && Math.abs(target.body!.velocity.y) < 50) return;
      const ghost = scene.add.sprite(target.x, target.y, target.texture.key)
        .setAlpha(0.4).setTint(0x06b6d4).setScale(target.scaleX, target.scaleY);
      trail.push(ghost);
      scene.tweens.add({
        targets: ghost, alpha: 0, scale: 0.5, duration: 200,
        onComplete: () => { ghost.destroy(); trail.splice(trail.indexOf(ghost), 1); }
      });
    }
  });
  return trail;
}

