// Circle close (like Mario)
function circleClose(scene: Phaser.Scene, targetScene: string, focusX: number, focusY: number) {
  const { width, height } = scene.scale;
  const maxRadius = Math.max(width, height);
  const mask = scene.add.graphics().setScrollFactor(0).setDepth(9999);
  let radius = maxRadius;

  scene.tweens.add({
    targets: { radius: maxRadius },
    radius: 0,
    duration: 800,
    ease: "Power2",
    onUpdate: (tween) => {
      radius = tween.getValue();
      mask.clear();
      mask.fillStyle(0x000000, 1);
      mask.fillRect(0, 0, width, height);
      mask.fillStyle(0x000000, 0); // This creates the "hole" effect visually
    },
    onComplete: () => scene.scene.start(targetScene)
  });
}

