// Global event bus for cross-scene communication
class EventBus {
  private static emitter = new Phaser.Events.EventEmitter();

  static emit(event: string, ...args: any[]) {
    this.emitter.emit(event, ...args);
  }

  static on(event: string, fn: (...args: any[]) => void, context?: any) {
    this.emitter.on(event, fn, context);
  }

  static once(event: string, fn: (...args: any[]) => void, context?: any) {
    this.emitter.once(event, fn, context);
  }

  static off(event: string, fn?: (...args: any[]) => void, context?: any) {
    this.emitter.off(event, fn, context);
  }
}

