// Dash mechanic with cooldown
private canDash = true;
private dashCooldown = 800; // ms
private dashSpeed = 600;
private dashDuration = 150; // ms
private isDashing = false;

create() {
  // Shift key to dash
  const shift = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.SHIFT);
  shift.on("down", () => this.dash());
}

dash() {
  if (!this.canDash || this.isDashing) return;
  this.canDash = false;
  this.isDashing = true;

  // Determine dash direction from current movement or facing
  const body = this.player.body!;
  let dashX = 0, dashY = 0;
  const cursors = this.input.keyboard!.createCursorKeys();
  if (cursors.left.isDown) dashX = -1;
  else if (cursors.right.isDown) dashX = 1;
  if (cursors.up.isDown) dashY = -1;
  else if (cursors.down.isDown) dashY = 1;
  if (dashX === 0 && dashY === 0) dashX = this.player.flipX ? -1 : 1;

  // Normalize and apply
  const len = Math.sqrt(dashX * dashX + dashY * dashY);
  body.setVelocity((dashX / len) * this.dashSpeed, (dashY / len) * this.dashSpeed);

  // Visual: trail + invulnerable
  this.player.setAlpha(0.6);
  this.invulnerable = true;

  // End dash
  this.time.delayedCall(this.dashDuration, () => {
    this.isDashing = false;
    this.invulnerable = false;
    this.player.setAlpha(1);
  });

  // Cooldown
  this.time.delayedCall(this.dashCooldown, () => { this.canDash = true; });
}

// In update(): skip normal movement during dash
if (!this.isDashing) {
  // Normal movement logic...
}

// Double jump with limited air jumps
private maxJumps = 2;
private jumpsLeft = 2;
private jumpForce = -350;

create() {
  const cursors = this.input.keyboard!.createCursorKeys();
  cursors.up.on("down", () => this.tryJump());
  // Or space bar:
  const space = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);
  space.on("down", () => this.tryJump());
}

tryJump() {
  if (this.jumpsLeft > 0) {
    this.player.body!.setVelocityY(this.jumpForce);
    this.jumpsLeft--;

    // Visual feedback for second jump
    if (this.jumpsLeft === 0) {
      // Air jump particle burst at feet
      this.add.particles(this.player.x, this.player.y + 20, "particle", {
        speed: { min: 30, max: 80 },
        angle: { min: 60, max: 120 },
        scale: { start: 0.4, end: 0 },
        lifespan: 300,
        quantity: 6,
        emitting: false
      }).explode();
    }

    // Squash and stretch
    this.tweens.add({
      targets: this.player, scaleY: 1.2, scaleX: 0.8, duration: 80, yoyo: true
    });
  }
}

update() {
  // Reset jumps when touching ground
  if (this.player.body!.touching.down) {
    this.jumpsLeft = this.maxJumps;
  }

  // Coyote time: brief grace period after leaving edge
  if (!this.player.body!.touching.down && this.jumpsLeft === this.maxJumps) {
    this.time.delayedCall(100, () => {
      if (!this.player.body!.touching.down && this.jumpsLeft === this.maxJumps) {
        this.jumpsLeft = this.maxJumps - 1;
      }
    });
  }
}

// XP and level system with level-up effects
private xp = 0;
private level = 1;
private xpToNext = 100;
private xpBar!: Phaser.GameObjects.Graphics;
private levelText!: Phaser.GameObjects.Text;

create() {
  this.xpBar = this.add.graphics().setScrollFactor(0).setDepth(100);
  this.levelText = this.add.text(16, 90, "Lv.1", {
    fontSize: "16px", color: "#a855f7", fontStyle: "bold"
  }).setScrollFactor(0).setDepth(100);
  this.drawXPBar();
}

addXP(amount: number) {
  this.xp += amount;
  while (this.xp >= this.xpToNext) {
    this.xp -= this.xpToNext;
    this.levelUp();
  }
  this.drawXPBar();
}

levelUp() {
  this.level++;
  this.xpToNext = Math.floor(this.xpToNext * 1.4);
  this.levelText.setText(`Lv.${this.level}`);

  // Level-up effect
  const { width, height } = this.scale;
  const txt = this.add.text(width / 2, height / 2, "LEVEL UP!", {
    fontSize: "40px", color: "#a855f7", fontStyle: "bold"
  }).setOrigin(0.5).setScrollFactor(0).setDepth(500);
  this.tweens.add({
    targets: txt, scale: 1.5, alpha: 0, y: height / 2 - 50, duration: 1200,
    onComplete: () => txt.destroy()
  });

  // Flash
  this.cameras.main.flash(400, 168, 85, 247);

  // Heal on level up
  this.currentHp = this.maxHp;
  this.drawHpBar();
}

drawXPBar() {
  this.xpBar.clear();
  this.xpBar.fillStyle(0x333333, 1);
  this.xpBar.fillRect(60, 94, 150, 10);
  const ratio = this.xp / this.xpToNext;
  this.xpBar.fillStyle(0xa855f7, 1);
  this.xpBar.fillRect(60, 94, 150 * ratio, 10);
}

