// Dash with afterimage trail effect
let canDash = true;
const dashSpeed = 600;
const dashDuration = 150;

function dash(player: Phaser.Physics.Arcade.Sprite, scene: Phaser.Scene) {
  if (!canDash) return;
  canDash = false;
  const dir = player.flipX ? -1 : 1;
  player.body!.setVelocityX(dir * dashSpeed);

  // Spawn afterimage ghosts
  for (let i = 0; i < 3; i++) {
    scene.time.delayedCall(i * 50, () => {
      const ghost = scene.add.sprite(player.x, player.y, player.texture.key)
        .setAlpha(0.5).setTint(0x00ccff).setFlipX(player.flipX);
      scene.tweens.add({ targets: ghost, alpha: 0, duration: 300, onComplete: () => ghost.destroy() });
    });
  }

  scene.time.delayedCall(dashDuration, () => player.body!.setVelocityX(0));
  scene.time.delayedCall(800, () => { canDash = true; });
}

