// Rope swing mechanic using distance constraint
let ropeJoint: Phaser.Physics.Arcade.Sprite | null = null;
const ropeLength = 200;

function attachRope(player: Phaser.Physics.Arcade.Sprite, anchorX: number, anchorY: number, scene: Phaser.Scene) {
  ropeJoint = scene.add.sprite(anchorX, anchorY, '__WHITE') as any;
  // Simulate pendulum in update
}

// In update(): simulate rope constraint
if (ropeJoint) {
  const dx = player.x - ropeJoint.x;
  const dy = player.y - ropeJoint.y;
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist > ropeLength) {
    const angle = Math.atan2(dy, dx);
    player.setPosition(
      ropeJoint.x + Math.cos(angle) * ropeLength,
      ropeJoint.y + Math.sin(angle) * ropeLength
    );
    // tangential velocity
    const nx = dx / dist, ny = dy / dist;
    const dot = player.body!.velocity.x * nx + player.body!.velocity.y * ny;
    player.body!.velocity.x -= dot * nx;
    player.body!.velocity.y -= dot * ny;
  }
  // Draw rope line
  scene.add.line(0, 0, ropeJoint.x, ropeJoint.y, player.x, player.y, 0xffffff).setOrigin(0).setDepth(-1);
}

