// Enemy state machine: idle → patrol → chase → attack → flee
type EnemyState = "idle" | "patrol" | "chase" | "attack" | "flee";
let state: EnemyState = "patrol";
const DETECT_RANGE = 200;
const ATTACK_RANGE = 40;
const FLEE_HP = 20;

// In update():
const dist = Phaser.Math.Distance.Between(enemy.x, enemy.y, player.x, player.y);

switch (state) {
  case "patrol":
    enemy.body!.setVelocityX(enemy.flipX ? -60 : 60);
    if (dist < DETECT_RANGE) state = "chase";
    break;
  case "chase":
    const dir = player.x < enemy.x ? -1 : 1;
    enemy.body!.setVelocityX(dir * 120);
    enemy.setFlipX(dir < 0);
    if (dist < ATTACK_RANGE) state = "attack";
    if (dist > DETECT_RANGE * 1.5) state = "patrol";
    if (enemyHP < FLEE_HP) state = "flee";
    break;
  case "attack":
    enemy.body!.setVelocityX(0);
    // attack logic...
    if (dist > ATTACK_RANGE * 2) state = "chase";
    break;
  case "flee":
    const fleeDir = player.x < enemy.x ? 1 : -1;
    enemy.body!.setVelocityX(fleeDir * 150);
    break;
}

// Boids flocking: separation + alignment + cohesion
interface Boid { sprite: Phaser.Physics.Arcade.Sprite; vx: number; vy: number; }
const boids: Boid[] = [];
const NEIGHBOR_DIST = 100;
const SEP_DIST = 30;

function updateBoids() {
  for (const b of boids) {
    let sepX = 0, sepY = 0, aliX = 0, aliY = 0, cohX = 0, cohY = 0, count = 0;
    for (const other of boids) {
      if (other === b) continue;
      const d = Phaser.Math.Distance.Between(b.sprite.x, b.sprite.y, other.sprite.x, other.sprite.y);
      if (d < NEIGHBOR_DIST) {
        aliX += other.vx; aliY += other.vy;
        cohX += other.sprite.x; cohY += other.sprite.y;
        count++;
        if (d < SEP_DIST) { sepX += b.sprite.x - other.sprite.x; sepY += b.sprite.y - other.sprite.y; }
      }
    }
    if (count > 0) {
      b.vx += sepX * 0.05 + (aliX / count - b.vx) * 0.02 + (cohX / count - b.sprite.x) * 0.01;
      b.vy += sepY * 0.05 + (aliY / count - b.vy) * 0.02 + (cohY / count - b.sprite.y) * 0.01;
    }
    const speed = Math.sqrt(b.vx * b.vx + b.vy * b.vy);
    if (speed > 150) { b.vx = (b.vx / speed) * 150; b.vy = (b.vy / speed) * 150; }
    b.sprite.body!.setVelocity(b.vx, b.vy);
  }
}

// Boss fight with multiple phases
const BOSS_MAX_HP = 300;
let bossHP = BOSS_MAX_HP;
let bossPhase = 1;

function updateBoss(boss: Phaser.Physics.Arcade.Sprite, player: Phaser.Physics.Arcade.Sprite, scene: Phaser.Scene) {
  const hpRatio = bossHP / BOSS_MAX_HP;
  if (hpRatio > 0.66) bossPhase = 1;
  else if (hpRatio > 0.33) bossPhase = 2;
  else bossPhase = 3;

  switch (bossPhase) {
    case 1: // Slow chase
      scene.physics.moveToObject(boss, player, 60);
      break;
    case 2: // Shoot projectiles
      scene.physics.moveToObject(boss, player, 40);
      if (Phaser.Math.Between(0, 60) === 0) spawnBossProjectile(boss, player, scene);
      break;
    case 3: // Enraged — fast + shoot
      scene.physics.moveToObject(boss, player, 140);
      boss.setTint(0xff4444);
      if (Phaser.Math.Between(0, 30) === 0) spawnBossProjectile(boss, player, scene);
      break;
  }
}

function spawnBossProjectile(boss: Phaser.Physics.Arcade.Sprite, player: Phaser.Physics.Arcade.Sprite, scene: Phaser.Scene) {
  const proj = scene.physics.add.sprite(boss.x, boss.y, "projectile");
  scene.physics.moveToObject(proj, player, 200);
  scene.time.delayedCall(3000, () => proj.destroy());
}

// Turret that rotates and shoots at player
const TURRET_RANGE = 300;
const FIRE_RATE = 1500; // ms
let lastFired = 0;

function updateTurret(turret: Phaser.GameObjects.Sprite, player: Phaser.Physics.Arcade.Sprite, scene: Phaser.Scene, time: number) {
  const dist = Phaser.Math.Distance.Between(turret.x, turret.y, player.x, player.y);
  if (dist > TURRET_RANGE) return;

  const angle = Phaser.Math.Angle.Between(turret.x, turret.y, player.x, player.y);
  turret.setRotation(angle);

  if (time - lastFired > FIRE_RATE) {
    lastFired = time;
    const bullet = scene.physics.add.sprite(turret.x, turret.y, "bullet");
    scene.physics.velocityFromRotation(angle, 300, bullet.body!.velocity as Phaser.Math.Vector2);
    scene.time.delayedCall(2000, () => bullet.destroy());
  }
}

