// Simple dungeon generation with connected rooms
interface Room { x: number; y: number; w: number; h: number; }
const TILE = 32;
const rooms: Room[] = [];

function generateDungeon(cols: number, rows: number, roomCount: number): number[][] {
  const map = Array.from({ length: rows }, () => Array(cols).fill(1)); // 1=wall
  for (let i = 0; i < roomCount; i++) {
    const w = Phaser.Math.Between(4, 8);
    const h = Phaser.Math.Between(4, 8);
    const x = Phaser.Math.Between(1, cols - w - 1);
    const y = Phaser.Math.Between(1, rows - h - 1);
    rooms.push({ x, y, w, h });
    for (let ry = y; ry < y + h; ry++)
      for (let rx = x; rx < x + w; rx++) map[ry][rx] = 0; // carve room
  }
  // Connect rooms with corridors
  for (let i = 1; i < rooms.length; i++) {
    const a = rooms[i - 1], b = rooms[i];
    const ax = Math.floor(a.x + a.w / 2), ay = Math.floor(a.y + a.h / 2);
    const bx = Math.floor(b.x + b.w / 2), by = Math.floor(b.y + b.h / 2);
    for (let x = Math.min(ax, bx); x <= Math.max(ax, bx); x++) map[ay][x] = 0;
    for (let y = Math.min(ay, by); y <= Math.max(ay, by); y++) map[y][bx] = 0;
  }
  return map;
}

// Procedural side-scrolling terrain using midpoint displacement
const TERRAIN_SEGMENTS = 40;
const TERRAIN_WIDTH = 50;
let terrainHeights: number[] = [];

function generateTerrain(scene: Phaser.Scene, baseY: number) {
  terrainHeights = [baseY];
  for (let i = 1; i <= TERRAIN_SEGMENTS; i++) {
    const prev = terrainHeights[i - 1];
    const delta = Phaser.Math.Between(-30, 30);
    terrainHeights.push(Phaser.Math.Clamp(prev + delta, baseY - 100, baseY + 60));
  }
  const gfx = scene.add.graphics();
  gfx.fillStyle(0x4a7c59);
  gfx.beginPath();
  gfx.moveTo(0, scene.scale.height);
  for (let i = 0; i < terrainHeights.length; i++) {
    gfx.lineTo(i * TERRAIN_WIDTH, terrainHeights[i]);
  }
  gfx.lineTo(TERRAIN_SEGMENTS * TERRAIN_WIDTH, scene.scale.height);
  gfx.closePath();
  gfx.fillPath();
  return gfx;
}

// Weighted random loot table
interface LootEntry { id: string; name: string; weight: number; rarity: string; }

const LOOT_TABLE: LootEntry[] = [
  { id: "coin", name: "Gold Coin", weight: 50, rarity: "common" },
  { id: "potion", name: "Health Potion", weight: 25, rarity: "uncommon" },
  { id: "gem", name: "Ruby Gem", weight: 15, rarity: "rare" },
  { id: "sword", name: "Magic Sword", weight: 8, rarity: "epic" },
  { id: "crown", name: "Ancient Crown", weight: 2, rarity: "legendary" },
];

function rollLoot(count: number = 1): LootEntry[] {
  const totalWeight = LOOT_TABLE.reduce((sum, e) => sum + e.weight, 0);
  const results: LootEntry[] = [];
  for (let i = 0; i < count; i++) {
    let roll = Math.random() * totalWeight;
    for (const entry of LOOT_TABLE) {
      roll -= entry.weight;
      if (roll <= 0) { results.push(entry); break; }
    }
  }
  return results;
}

