// Swipe gesture detection
let swipeStart: { x: number; y: number; time: number } | null = null;
const MIN_SWIPE_DIST = 50;
const MAX_SWIPE_TIME = 300;

this.input.on("pointerdown", (p: Phaser.Input.Pointer) => {
  swipeStart = { x: p.x, y: p.y, time: p.time };
});

this.input.on("pointerup", (p: Phaser.Input.Pointer) => {
  if (!swipeStart) return;
  const dx = p.x - swipeStart.x;
  const dy = p.y - swipeStart.y;
  const dt = p.time - swipeStart.time;
  const dist = Math.sqrt(dx * dx + dy * dy);

  if (dist >= MIN_SWIPE_DIST && dt <= MAX_SWIPE_TIME) {
    if (Math.abs(dx) > Math.abs(dy)) {
      // Horizontal swipe
      if (dx > 0) onSwipe("right");
      else onSwipe("left");
    } else {
      // Vertical swipe
      if (dy > 0) onSwipe("down");
      else onSwipe("up");
    }
  }
  swipeStart = null;
});

