// Toast notification system
const toastQueue: string[] = [];
let toastActive = false;

function showToast(scene: Phaser.Scene, message: string) {
  toastQueue.push(message);
  if (!toastActive) processToast(scene);
}

function processToast(scene: Phaser.Scene) {
  if (toastQueue.length === 0) { toastActive = false; return; }
  toastActive = true;
  const msg = toastQueue.shift()!;
  const { width } = scene.scale;
  const bg = scene.add.rectangle(width / 2, -30, 280, 40, 0x222222, 0.9)
    .setStrokeStyle(1, 0x4ade80).setScrollFactor(0).setDepth(9999);
  const txt = scene.add.text(width / 2, -30, msg, { fontSize: "16px", color: "#4ade80" })
    .setOrigin(0.5).setScrollFactor(0).setDepth(10000);

  scene.tweens.add({ targets: [bg, txt], y: 40, duration: 300, ease: "Back.easeOut",
    onComplete: () => {
      scene.time.delayedCall(1500, () => {
        scene.tweens.add({ targets: [bg, txt], y: -30, alpha: 0, duration: 300,
          onComplete: () => { bg.destroy(); txt.destroy(); processToast(scene); }
        });
      });
    }
  });
}

