// Radial / pie menu
const MENU_ITEMS = ["Attack", "Magic", "Item", "Defend", "Run"];
const RADIUS = 80;
let menuContainer: Phaser.GameObjects.Container | null = null;

function openRadialMenu(scene: Phaser.Scene, cx: number, cy: number) {
  closeRadialMenu();
  menuContainer = scene.add.container(cx, cy).setDepth(5000).setScrollFactor(0);
  // Center circle
  menuContainer.add(scene.add.circle(0, 0, 20, 0x333333, 0.8));

  MENU_ITEMS.forEach((item, i) => {
    const angle = (i / MENU_ITEMS.length) * Math.PI * 2 - Math.PI / 2;
    const x = Math.cos(angle) * RADIUS;
    const y = Math.sin(angle) * RADIUS;
    const btn = scene.add.circle(x, y, 28, 0x444444, 0.9).setInteractive({ useHandCursor: true });
    const label = scene.add.text(x, y, item, { fontSize: "12px", color: "#fff" }).setOrigin(0.5);
    btn.on("pointerdown", () => { onMenuSelect(item); closeRadialMenu(); });
    btn.on("pointerover", () => btn.setFillStyle(0x666666));
    btn.on("pointerout", () => btn.setFillStyle(0x444444));
    menuContainer!.add([btn, label]);
  });
}

function closeRadialMenu() { menuContainer?.destroy(); menuContainer = null; }
function onMenuSelect(item: string) { console.log("Selected:", item); }

// Drag-and-drop inventory with slot swapping
const SLOT_COUNT = 8;
const SLOT_W = 56;
interface InvSlot { bg: Phaser.GameObjects.Rectangle; item: Phaser.GameObjects.Sprite | null; index: number; }
const slots: InvSlot[] = [];

for (let i = 0; i < SLOT_COUNT; i++) {
  const x = 40 + i * (SLOT_W + 8);
  const bg = this.add.rectangle(x, 40, SLOT_W, SLOT_W, 0x333333).setStrokeStyle(1, 0x666666);
  slots.push({ bg, item: null, index: i });
}

function placeItem(slotIdx: number, key: string, scene: Phaser.Scene) {
  const s = slots[slotIdx];
  const item = scene.add.sprite(s.bg.x, s.bg.y, key).setInteractive({ draggable: true });
  s.item = item;

  scene.input.setDraggable(item);
  item.on("drag", (_p: any, dx: number, dy: number) => item.setPosition(dx, dy));
  item.on("dragend", () => {
    const target = slots.find(sl => {
      const d = Phaser.Math.Distance.Between(item.x, item.y, sl.bg.x, sl.bg.y);
      return d < SLOT_W / 2;
    });
    if (target && target !== s) {
      // Swap
      const tmp = target.item;
      target.item = item;
      s.item = tmp;
      item.setPosition(target.bg.x, target.bg.y);
      if (tmp) tmp.setPosition(s.bg.x, s.bg.y);
    } else {
      item.setPosition(s.bg.x, s.bg.y); // snap back
    }
  });
}

// Crafting system with recipes
interface Recipe { result: string; ingredients: Record<string, number>; }
const RECIPES: Recipe[] = [
  { result: "torch", ingredients: { stick: 1, coal: 1 } },
  { result: "sword", ingredients: { iron: 2, stick: 1 } },
  { result: "health_potion", ingredients: { herb: 3, water: 1 } },
  { result: "shield", ingredients: { iron: 3, wood: 2 } },
];

const inventory: Record<string, number> = { stick: 5, coal: 3, iron: 4, herb: 6, water: 2, wood: 3 };

function canCraft(recipe: Recipe): boolean {
  return Object.entries(recipe.ingredients).every(([item, qty]) => (inventory[item] ?? 0) >= qty);
}

function craft(recipe: Recipe): boolean {
  if (!canCraft(recipe)) return false;
  for (const [item, qty] of Object.entries(recipe.ingredients)) {
    inventory[item] -= qty;
  }
  inventory[recipe.result] = (inventory[recipe.result] ?? 0) + 1;
  return true;
}

