// Farming: plant → grow → harvest
type CropStage = "seed" | "sprout" | "mature" | "harvestable";
interface Crop { sprite: Phaser.GameObjects.Sprite; stage: CropStage; timer: number; growTime: number; }
const crops: Crop[] = [];
const GROW_TIMES: Record<string, number> = { wheat: 5000, carrot: 8000, tomato: 12000 };

function plantCrop(scene: Phaser.Scene, x: number, y: number, type: string) {
  const sprite = scene.add.sprite(x, y, `${type}_seed`).setInteractive();
  const crop: Crop = { sprite, stage: "seed", timer: 0, growTime: GROW_TIMES[type] || 5000 };
  crops.push(crop);
  sprite.on("pointerdown", () => { if (crop.stage === "harvestable") harvest(crop); });
}

// In update(time, delta):
for (const crop of crops) {
  if (crop.stage === "harvestable") continue;
  crop.timer += delta;
  const progress = crop.timer / crop.growTime;
  if (progress >= 1) { crop.stage = "harvestable"; crop.sprite.setTint(0xffdd44); }
  else if (progress >= 0.6) { crop.stage = "mature"; crop.sprite.setScale(1.2); }
  else if (progress >= 0.2) { crop.stage = "sprout"; crop.sprite.setScale(0.8); }
}

function harvest(crop: Crop) {
  crop.sprite.destroy();
  crops.splice(crops.indexOf(crop), 1);
  // Add to inventory...
}

// Fishing mini-game
let fishingState: "idle" | "casting" | "waiting" | "reeling" = "idle";
let biteTimer = 0;
let reelProgress = 0;
const REEL_TARGET = 100;

function castLine(scene: Phaser.Scene) {
  fishingState = "casting";
  scene.tweens.add({
    targets: bobber, y: bobber.y + 40, duration: 500, ease: "Bounce.easeOut",
    onComplete: () => {
      fishingState = "waiting";
      biteTimer = Phaser.Math.Between(2000, 6000);
    }
  });
}

// In update(time, delta):
if (fishingState === "waiting") {
  biteTimer -= delta;
  if (biteTimer <= 0) {
    fishingState = "reeling";
    reelProgress = 0;
    bobber.setTint(0xff4444); // visual cue: fish biting!
  }
}
if (fishingState === "reeling") {
  // Player must press SPACE rapidly to reel in
  if (Phaser.Input.Keyboard.JustDown(spaceKey)) {
    reelProgress += 10 + Phaser.Math.Between(0, 5);
  }
  reelProgress -= delta * 0.02; // fish fights back
  reelProgress = Math.max(0, reelProgress);
  if (reelProgress >= REEL_TARGET) {
    // Caught!
    fishingState = "idle";
    const fish = ["Trout", "Bass", "Salmon", "Goldfish"][Phaser.Math.Between(0, 3)];
    console.log("Caught:", fish);
  }
}

// Stealth detection cone
const CONE_RANGE = 200;
const CONE_ANGLE = Math.PI / 3; // 60 degrees

function isPlayerDetected(enemy: Phaser.GameObjects.Sprite, player: Phaser.GameObjects.Sprite): boolean {
  const dist = Phaser.Math.Distance.Between(enemy.x, enemy.y, player.x, player.y);
  if (dist > CONE_RANGE) return false;

  const facingAngle = enemy.flipX ? Math.PI : 0; // direction enemy faces
  const angleToPlayer = Phaser.Math.Angle.Between(enemy.x, enemy.y, player.x, player.y);
  const diff = Phaser.Math.Angle.Wrap(angleToPlayer - facingAngle);

  return Math.abs(diff) < CONE_ANGLE / 2;
}

// Draw debug vision cone
function drawCone(scene: Phaser.Scene, enemy: Phaser.GameObjects.Sprite, detected: boolean) {
  const gfx = scene.add.graphics();
  const facing = enemy.flipX ? Math.PI : 0;
  gfx.fillStyle(detected ? 0xff4444 : 0x44ff44, 0.15);
  gfx.beginPath();
  gfx.moveTo(enemy.x, enemy.y);
  gfx.arc(enemy.x, enemy.y, CONE_RANGE, facing - CONE_ANGLE / 2, facing + CONE_ANGLE / 2);
  gfx.closePath();
  gfx.fillPath();
  return gfx;
}

// Grapple point / zip-line mechanic
const grapplePoints = this.physics.add.staticGroup();
// Add points: grapplePoints.create(300, 100, 'hook');

let isGrappling = false;
let grappleTarget: { x: number; y: number } | null = null;
const GRAPPLE_SPEED = 400;

function findNearestGrapple(px: number, py: number, maxDist: number) {
  let nearest: Phaser.Physics.Arcade.Sprite | null = null;
  let minDist = maxDist;
  grapplePoints.getChildren().forEach((g) => {
    const gp = g as Phaser.Physics.Arcade.Sprite;
    const d = Phaser.Math.Distance.Between(px, py, gp.x, gp.y);
    if (d < minDist) { minDist = d; nearest = gp; }
  });
  return nearest;
}

function startGrapple(player: Phaser.Physics.Arcade.Sprite) {
  const target = findNearestGrapple(player.x, player.y, 250);
  if (!target) return;
  isGrappling = true;
  grappleTarget = { x: target.x, y: target.y };
  player.body!.setAllowGravity(false);
  this.physics.moveToObject(player, target, GRAPPLE_SPEED);
}

// In update():
if (isGrappling && grappleTarget) {
  const dist = Phaser.Math.Distance.Between(player.x, player.y, grappleTarget.x, grappleTarget.y);
  if (dist < 10) {
    isGrappling = false;
    grappleTarget = null;
    player.body!.setAllowGravity(true);
    player.body!.setVelocityY(-200); // launch upward
  }
}

