// Cinematic camera path through waypoints
const WAYPOINTS = [
  { x: 100, y: 200, zoom: 1, duration: 2000 },
  { x: 600, y: 150, zoom: 1.5, duration: 3000 },
  { x: 400, y: 400, zoom: 1, duration: 2000 },
];

function playCinematic(scene: Phaser.Scene) {
  const cam = scene.cameras.main;
  cam.stopFollow();
  let delay = 0;

  WAYPOINTS.forEach((wp) => {
    scene.time.delayedCall(delay, () => {
      cam.pan(wp.x, wp.y, wp.duration, "Sine.easeInOut");
      cam.zoomTo(wp.zoom, wp.duration, "Sine.easeInOut");
    });
    delay += wp.duration;
  });

  // Return to player after cinematic
  scene.time.delayedCall(delay + 500, () => {
    cam.zoomTo(1, 1000);
    cam.startFollow(player, true, 0.1, 0.1);
  });
}

