// Reusable Phaser plugin pattern
class DamageNumberPlugin extends Phaser.Plugins.ScenePlugin {
  constructor(scene: Phaser.Scene, pluginManager: Phaser.Plugins.PluginManager, pluginKey: string) {
    super(scene, pluginManager, pluginKey);
  }

  boot() {
    this.scene!.events.on("shutdown", this.shutdown, this);
  }

  show(x: number, y: number, amount: number, color = "#ff4444") {
    const txt = this.scene!.add.text(x, y, `-${amount}`, {
      fontSize: "20px", color, fontStyle: "bold"
    }).setOrigin(0.5).setDepth(9999);

    this.scene!.tweens.add({
      targets: txt, y: y - 50, alpha: 0, duration: 800,
      ease: "Power2", onComplete: () => txt.destroy()
    });
  }

  shutdown() { /* cleanup */ }
}

